esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS log_fs_free_pct = MAX(LAST_OVER_TIME(ibmmq_qmgr_log_file_system_free_space_percentage))
    BY attributes.qmgr
// Alert when log filesystem free space drops below 10%
// Log filesystem exhaustion halts all transactional operations
// Adjust threshold based on your capacity planning requirements
| WHERE log_fs_free_pct IS NOT NULL AND log_fs_free_pct < 10
